SELECT , CASE WHEN pl.id IS NOT NULL THEN 1 ELSE 0 END as is_liked, CASE WHEN pf.id IS NOT NULL THEN 1 ELSE 0 END as is_favorited FROM post p LEFT JOIN user u ON p.user_id = u.id LEFT JOIN post_like pl ON p.id = pl.post_id AND pl.user_id = #{userId} LEFT JOIN post_favorite pf ON p.id = pf.post_id AND pf.user_id = #{userId} WHERE p.status = 1
AND p.category = #{category}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.is_top DESC,
p.like_count DESC, p.comment_count DESC, p.create_time DESC, p.create_time DESC
p.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM post p WHERE p.status = 1
AND p.category = #{category}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))

